-- activityLog table creation and population
-- This table stores individual activity log entries with activity references and durations

DROP TABLE IF EXISTS activityLog;

CREATE TABLE activityLog (
    id INT AUTO_INCREMENT PRIMARY KEY,
    fkActivityId INT NOT NULL,
    date DATE NOT NULL,
    duration INT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_activity (fkActivityId),
    INDEX idx_date (date),
    FOREIGN KEY (fkActivityId) REFERENCES activities(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

